import React, { useEffect, useRef, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import './ArticleGrid.css';

// Grid pagination component with gold frames - Shows 10 articles per page
const ArticleGrid = ({ articles }) => {
    const navigate = useNavigate();
    const [currentPage, setCurrentPage] = useState(1);
    const articlesPerPage = 10;

    // Calculate pagination
    const totalPages = Math.ceil(articles.length / articlesPerPage);
    const startIndex = (currentPage - 1) * articlesPerPage;
    const endIndex = startIndex + articlesPerPage;
    const currentArticles = articles.slice(startIndex, endIndex);

    const handleArticleClick = (id) => {
        navigate(`/article/${id}`);
    };

    const handleNextPage = () => {
        if (currentPage < totalPages) {
            setCurrentPage(currentPage + 1);
            // Scroll carousel to top
            if (carouselRef.current) {
                carouselRef.current.scrollLeft = 0;
            }
        }
    };

    const handlePrevPage = () => {
        if (currentPage > 1) {
            setCurrentPage(currentPage - 1);
            // Scroll carousel to top
            if (carouselRef.current) {
                carouselRef.current.scrollLeft = 0;
            }
        }
    };

    useEffect(() => {
        const carousel = carouselRef.current;
        if (!carousel) return;

        let scrollPosition = 0;
        let animationFrameId = null;

        const scroll = () => {
            if (!isHovering) {
                scrollPosition += 1;
                carousel.scrollLeft = scrollPosition;

                // Infinite loop: when reaching end, jump back to start seamlessly
                if (carousel.scrollLeft >= carousel.scrollWidth - carousel.clientWidth) {
                    scrollPosition = 0;
                    carousel.scrollLeft = 0;
                }
            }
            animationFrameId = requestAnimationFrame(scroll);
        };

        animationFrameId = requestAnimationFrame(scroll);

        return () => {
            if (animationFrameId) {
                cancelAnimationFrame(animationFrameId);
            }
        };
    }, [isHovering, currentPage]);

    return (
        <div className="article-carousel-section">
            {/* Grid Layout - 10 articles per page */}
            <div className="articles-grid">
                {currentArticles.map((article) => (
                    <div 
                        key={article.id}
                        className="grid-article-item"
                        onClick={() => handleArticleClick(article.id)}
                    >
                        <div className="article-image-wrapper">
                            <img 
                                src={article.image} 
                                alt={article.title}
                                className="article-grid-image"
                                loading="lazy"
                                draggable="false"
                            />
                            <div className="article-overlay">
                                <div className="overlay-content">
                                    <h3 className="overlay-title">{article.title}</h3>
                                    <p className="overlay-category">{article.category}</p>
                                </div>
                            </div>
                        </div>
                    </div>
                ))}
            </div>

            {/* Pagination Controls */}
            <div className="pagination-controls">
                <button 
                    className="pagination-btn prev-btn"
                    onClick={handlePrevPage}
                    disabled={currentPage === 1}
                    aria-label="Previous page"
                >
                    ← Previous
                </button>

                <div className="pagination-info">
                    <span className="page-indicator">Page {currentPage} of {totalPages}</span>
                </div>

                <button 
                    className="pagination-btn next-btn"
                    onClick={handleNextPage}
                    disabled={currentPage === totalPages}
                    aria-label="Next page"
                >
                    Next →
                </button>
            </div>
        </div>
    );
};

export default ArticleGrid;
